/**
 * SMS channel handler — listens for notification:requested events
 * and delivers them via SMS (in-memory for this demo).
 */
export class SmsChannelHandler implements NotificationChannelHandler {
  readonly channel = 'sms';
  private logger = new Logger('SmsChannelHandler');
  private deliveredNotifications: DeliveredNotification[] = [];

  constructor(private eventBus: EventBus) {
    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
      if (event.channel === this.channel) {
        this.handle(event);
      }
    });
  }

  handle(event: NotificationRequestedEvent): void {
    const notification: DeliveredNotification = {
      id: generateNotificationId(),
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      channel: this.channel,
      sentAt: new Date(),
    };
    this.deliveredNotifications.push(notification);
    this.logger.info(`SMS sent: ${notification.id} to ${event.recipient}`);
  }

  getDeliveredNotifications(): DeliveredNotification[] {
    return [...this.deliveredNotifications];
  }

  clearNotifications(): void {
    this.deliveredNotifications = [];
  }
}

export interface WebhookPayload {
  recipient: string;
  subject: string;
  body: string;
  channel: string;
  deliveredAt: string;
}

/**
 * Webhook channel handler — listens for notification:requested events
 * and delivers them via webhook POST (in-memory for this demo).
 */
export class WebhookChannelHandler implements NotificationChannelHandler {
  readonly channel = 'webhook';
  private logger = new Logger('WebhookChannelHandler');
  private deliveredNotifications: DeliveredNotification[] = [];
  private deliveredPayloads: WebhookPayload[] = [];

  constructor(
    private eventBus: EventBus,
    private webhookUrl: string,
  ) {
    this.eventBus.on<NotificationRequestedEvent>('notification:requested', (event) => {
      if (event.channel === this.channel) {
        this.handle(event);
      }
    });
  }

  handle(event: NotificationRequestedEvent): void {
    const now = new Date();
    const notification: DeliveredNotification = {
      id: generateNotificationId(),
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      channel: this.channel,
      sentAt: now,
    };
    this.deliveredNotifications.push(notification);

    const payload: WebhookPayload = {
      recipient: event.recipient,
      subject: event.subject,
      body: event.body,
      channel: this.channel,
      deliveredAt: now.toISOString(),
    };
    this.deliveredPayloads.push(payload);
    this.logger.info(`Webhook POST to ${this.webhookUrl}: ${notification.id}`);
  }

  getDeliveredNotifications(): DeliveredNotification[] {
    return [...this.deliveredNotifications];
  }

  getDeliveredPayloads(): WebhookPayload[] {
    return [...this.deliveredPayloads];
  }

  getWebhookUrl(): string {
    return this.webhookUrl;
  }

  clearNotifications(): void {
    this.deliveredNotifications = [];
    this.deliveredPayloads = [];
  }
}

