describe('SmsChannelHandler', () => {
  let eventBus: EventBus;
  let smsHandler: SmsChannelHandler;

  beforeEach(() => {
    eventBus = new EventBus();
    smsHandler = new SmsChannelHandler(eventBus);
    resetNotificationIdCounter();
  });

  it('should deliver SMS notifications from EventBus', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: '+1234567890',
      subject: 'Order Update',
      body: 'Your order has shipped!',
      channel: 'sms',
      timestamp: new Date(),
    });

    const delivered = smsHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.recipient).toBe('+1234567890');
    expect(delivered[0]?.subject).toBe('Order Update');
    expect(delivered[0]?.body).toBe('Your order has shipped!');
    expect(delivered[0]?.channel).toBe('sms');
  });

  it('should ignore notifications for other channels', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'alice@example.com',
      subject: 'Email Alert',
      body: 'This is an email',
      channel: 'email',
      timestamp: new Date(),
    });

    const delivered = smsHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(0);
  });

  it('should handle multiple notifications', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: '+1234567890',
      subject: 'First',
      body: 'First SMS',
      channel: 'sms',
      timestamp: new Date(),
    });
    await eventBus.emit({
      type: 'notification:requested',
      recipient: '+0987654321',
      subject: 'Second',
      body: 'Second SMS',
      channel: 'sms',
      timestamp: new Date(),
    });

    const delivered = smsHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(2);
    expect(delivered[0]?.recipient).toBe('+1234567890');
    expect(delivered[1]?.recipient).toBe('+0987654321');
  });

  it('should generate sequential IDs for delivered notifications', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: '+1234567890',
      subject: 'First',
      body: 'First',
      channel: 'sms',
      timestamp: new Date(),
    });
    await eventBus.emit({
      type: 'notification:requested',
      recipient: '+0987654321',
      subject: 'Second',
      body: 'Second',
      channel: 'sms',
      timestamp: new Date(),
    });

    const delivered = smsHandler.getDeliveredNotifications();
    expect(delivered[0]?.id).toBe('notif-0001');
    expect(delivered[1]?.id).toBe('notif-0002');
  });

  it('should work end-to-end with NotificationService', async () => {
    statusChangeCallbacks.clear();
    const service = new NotificationService(eventBus);

    service.sendNotification({
      recipient: '+1234567890',
      subject: 'SMS Test',
      body: 'Hello via SMS',
      channel: 'sms',
    });

    const delivered = smsHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.recipient).toBe('+1234567890');
    expect(delivered[0]?.channel).toBe('sms');
  });
});

describe('WebhookChannelHandler', () => {
  let eventBus: EventBus;
  let webhookHandler: WebhookChannelHandler;
  const testWebhookUrl = 'https://hooks.example.com/notify';

  beforeEach(() => {
    eventBus = new EventBus();
    webhookHandler = new WebhookChannelHandler(eventBus, testWebhookUrl);
    resetNotificationIdCounter();
  });

  it('should deliver webhook notifications from EventBus', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'system-alert',
      subject: 'Deploy Complete',
      body: 'v2.0 deployed successfully',
      channel: 'webhook',
      timestamp: new Date(),
    });

    const delivered = webhookHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.recipient).toBe('system-alert');
    expect(delivered[0]?.subject).toBe('Deploy Complete');
    expect(delivered[0]?.body).toBe('v2.0 deployed successfully');
    expect(delivered[0]?.channel).toBe('webhook');
  });

  it('should ignore notifications for other channels', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'alice@example.com',
      subject: 'Email Alert',
      body: 'This is an email',
      channel: 'email',
      timestamp: new Date(),
    });

    const delivered = webhookHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(0);
  });

  it('should track webhook payloads', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'system-alert',
      subject: 'Deploy Complete',
      body: 'v2.0 deployed successfully',
      channel: 'webhook',
      timestamp: new Date(),
    });

    const payloads = webhookHandler.getDeliveredPayloads();
    expect(payloads).toHaveLength(1);
    expect(payloads[0]).toMatchObject({
      recipient: 'system-alert',
      subject: 'Deploy Complete',
      body: 'v2.0 deployed successfully',
      channel: 'webhook',
    });
    expect(payloads[0]?.deliveredAt).toBeDefined();
  });

  it('should expose the configured webhook URL', () => {
    expect(webhookHandler.getWebhookUrl()).toBe(testWebhookUrl);
  });

  it('should handle multiple notifications', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'alert-1',
      subject: 'First',
      body: 'First webhook',
      channel: 'webhook',
      timestamp: new Date(),
    });
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'alert-2',
      subject: 'Second',
      body: 'Second webhook',
      channel: 'webhook',
      timestamp: new Date(),
    });

    const delivered = webhookHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(2);
    const payloads = webhookHandler.getDeliveredPayloads();
    expect(payloads).toHaveLength(2);
  });

  it('should generate sequential IDs for delivered notifications', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'alert-1',
      subject: 'First',
      body: 'First',
      channel: 'webhook',
      timestamp: new Date(),
    });
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'alert-2',
      subject: 'Second',
      body: 'Second',
      channel: 'webhook',
      timestamp: new Date(),
    });

    const delivered = webhookHandler.getDeliveredNotifications();
    expect(delivered[0]?.id).toBe('notif-0001');
    expect(delivered[1]?.id).toBe('notif-0002');
  });

  it('should clear both notifications and payloads', async () => {
    await eventBus.emit({
      type: 'notification:requested',
      recipient: 'alert-1',
      subject: 'Test',
      body: 'Test',
      channel: 'webhook',
      timestamp: new Date(),
    });

    webhookHandler.clearNotifications();
    expect(webhookHandler.getDeliveredNotifications()).toHaveLength(0);
    expect(webhookHandler.getDeliveredPayloads()).toHaveLength(0);
  });

  it('should work end-to-end with NotificationService', async () => {
    statusChangeCallbacks.clear();
    const service = new NotificationService(eventBus);

    service.sendNotification({
      recipient: 'system-alert',
      subject: 'Webhook Test',
      body: 'Hello via webhook',
      channel: 'webhook',
    });

    const delivered = webhookHandler.getDeliveredNotifications();
    expect(delivered).toHaveLength(1);
    expect(delivered[0]?.recipient).toBe('system-alert');
    expect(delivered[0]?.channel).toBe('webhook');

    const payloads = webhookHandler.getDeliveredPayloads();
    expect(payloads).toHaveLength(1);
  });
});

